# Category: oauth_security

import os
import uuid
import json
from datetime import datetime, timedelta

from flask import Flask, request, jsonify, redirect, url_for, session, render_template

app = Flask(__name__)
app.secret_key = os.urandom(24) # Replace with a strong, persistent key in production

# --- Configuration ---
# In a real application, these would come from a database or secure config
CLIENTS = {
    "test_client_id": {
        "client_secret": "test_client_secret",
        "registered_redirect_uri_base": "http://localhost:5001/callback", # The base URL for the client
        "scope": ["read", "write"]
    }
}

USERS = {
    "user1": {"password": "password123"}
}

# --- In-memory storage for tokens and authorization codes (for demonstration) ---
AUTHORIZATION_CODES = {} # code: {client_id, redirect_uri, scope, user_id, expires_at}
ACCESS_TOKENS = {}      # token: {client_id, user_id, scope, expires_at, refresh_token}
REFRESH_TOKENS = {}     # refresh_token: {access_token, client_id, user_id, scope, expires_at}

# --- Helper Functions ---
def generate_token(length=32):
    return uuid.uuid4().hex[:length]

def validate_redirect_uri(registered_base, requested_uri):
    """
    Validates a requested redirect_uri against a registered base URI using startswith.
    """
    if not registered_base or not requested_uri:
        return False
    return requested_uri.startswith(registered_base)

def get_client_info(client_id):
    return CLIENTS.get(client_id)

def get_user_info(username):
    return USERS.get(username)

def create_authorization_code(client_id, redirect_uri, scope, user_id):
    code = generate_token(64)
    AUTHORIZATION_CODES[code] = {
        "client_id": client_id,
        "redirect_uri": redirect_uri,
        "scope": scope,
        "user_id": user_id,
        "expires_at": datetime.utcnow() + timedelta(minutes=5)
    }
    return code

def create_access_token(client_id, user_id, scope, refresh_token=None):
    access_token = generate_token()
    new_refresh_token = generate_token()

    ACCESS_TOKENS[access_token] = {
        "client_id": client_id,
        "user_id": user_id,
        "scope": scope,
        "expires_at": datetime.utcnow() + timedelta(hours=1),
        "refresh_token": new_refresh_token
    }
    REFRESH_TOKENS[new_refresh_token] = {
        "client_id": client_id,
        "user_id": user_id,
        "scope": scope,
        "access_token": access_token,
        "expires_at": datetime.utcnow() + timedelta(days=7)
    }
    return access_token, new_refresh_token

# --- OAuth 2.0 Endpoints ---

@app.route('/authorize', methods=['GET'])
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    response_type = request.args.get('response_type')
    scope = request.args.get('scope')
    state = request.args.get('state')

    if not all([client_id, redirect_uri, response_type]):
        return jsonify({"error": "invalid_request", "error_description": "Missing required parameters"}), 400

    client_info = get_client_info(client_id)
    if not client_info:
        return jsonify({"error": "unauthorized_client", "error_description": "Client not found"}), 401

    if not validate_redirect_uri(client_info["registered_redirect_uri_base"], redirect_uri):
        # In a real scenario, you might redirect with an error fragment or query parameter
        # but for demonstration, a simple JSON response is fine for this specific error.
        return jsonify({"error": "invalid_request", "error_description": "Redirect URI mismatch"}), 400

    if response_type != "code":
        # Per RFC 6749, if response_type is unsupported, redirect with error
        error_url = f"{redirect_uri}?error=unsupported_response_type&error_description=Only%20'code'%20response%20type%20is%20supported"
        if state:
            error_url += f"&state={state}"
        return redirect(error_url)

    # In a real app, render a login/consent page
    session['oauth_params'] = {
        'client_id': client_id,
        'redirect_uri': redirect_uri,
        'scope': scope,
        'state': state
    }
    return render_template('login.html', client_id=client_id, scope=scope)

@app.route('/login', methods=['POST'])
def login():
    username = request.form.get('username')
    password = request.form.get('password')
    oauth_params = session.pop('oauth_params', None)

    if not oauth_params:
        return jsonify({"error": "server_error", "error_description": "OAuth parameters missing from session"}), 500

    client_id = oauth_params['client_id']
    redirect_uri = oauth_params['redirect_uri']
    scope = oauth_params['scope']
    state = oauth_params['state']

    user_info = get_user_info(username)
    if not user_info or user_info["password"] != password:
        # In a real app, you'd re-render the login page with an error
        return render_template('login.html', client_id=client_id, scope=scope, error="Invalid username or password")

    # User authenticated and consented (implied by successful login)
    auth_code = create_authorization_code(client_id, redirect_uri, scope, username)

    # Redirect back to client with authorization code
    redirect_to_client_url = f"{redirect_uri}?code={auth_code}"
    if state:
        redirect_to_client_url += f"&state={state}"
    return redirect(redirect_to_client_url)

@app.route('/token', methods=['POST'])
def token():
    grant_type = request.form.get('grant_type')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    client_info = get_client_info(client_id)
    if not client_info or client_info["client_secret"] != client_secret:
        return jsonify({"error": "unauthorized_client", "error_description": "Invalid client credentials"}), 401

    if grant_type == "authorization_code":
        code = request.form.get('code')
        redirect_uri = request.form.get('redirect_uri')

        auth_code_data = AUTHORIZATION_CODES.get(code)
        if not auth_code_data or auth_code_data["client_id"] != client_id or auth_code_data["redirect_uri"] != redirect_uri:
            return jsonify({"error": "invalid_grant", "error_description": "Invalid authorization code or redirect URI mismatch"}), 400
        if datetime.utcnow() > auth_code_data["expires_at"]:
            return jsonify({"error": "invalid_grant", "error_description": "Authorization code expired"}), 400

        # Code used, invalidate it immediately
        del AUTHORIZATION_CODES[code]

        access_token, refresh_token = create_access_token(
            auth_code_data["client_id"],
            auth_code_data["user_id"],
            auth_code_data["scope"]
        )

        return jsonify({
            "access_token": access_token,
            "token_type": "Bearer",
            "expires_in": 3600, # 1 hour
            "refresh_token": refresh_token,
            "scope": " ".join(auth_code_data["scope"])
        })

    elif grant_type == "refresh_token":
        refresh_token = request.form.get('refresh_token')
        refresh_token_data = REFRESH_TOKENS.get(refresh_token)

        if not refresh_token_data or refresh_token_data["client_id"] != client_id:
            return jsonify({"error": "invalid_grant", "error_description": "Invalid refresh token or client mismatch"}), 400
        if datetime.utcnow() > refresh_token_data["expires_at"]:
            return jsonify({"error": "invalid_grant", "error_description": "Refresh token expired"}), 400

        # Revoke old access token and create new ones
        old_access_token = refresh_token_data.get("access_token")
        if old_access_token in ACCESS_TOKENS:
            del ACCESS_TOKENS[old_access_token] # Invalidate old access token

        del REFRESH_TOKENS[refresh_token] # Invalidate old refresh token

        access_token, new_refresh_token = create_access_token(
            refresh_token_data["client_id"],
            refresh_token_data["user_id"],
            refresh_token_data["scope"]
        )

        return jsonify({
            "access_token": access_token,
            "token_type": "Bearer",
            "expires_in": 3600, # 1 hour
            "refresh_token": new_refresh_token,
            "scope": " ".join(refresh_token_data["scope"])
        })

    else:
        return jsonify({"error": "unsupported_grant_type", "error_description": "Only 'authorization_code' and 'refresh_token' grant types are supported"}), 400

@app.route('/userinfo', methods=['GET'])
def userinfo():
    auth_header = request.headers.get('Authorization')
    if not auth_header or not auth_header.startswith('Bearer '):
        return jsonify({"error": "invalid_token", "error_description": "Missing or malformed Authorization header"}), 401

    access_token = auth_header.split(' ')[1]
    token_data = ACCESS_TOKENS.get(access_token)

    if not token_data:
        return jsonify({"error": "invalid_token", "error_description": "Invalid access token"}), 401
    if datetime.utcnow() > token_data["expires_at"]:
        return jsonify({"error": "invalid_token", "error_description": "Access token expired"}), 401

    # In a real application, you'd fetch more detailed user info from a database
    # based on token_data["user_id"] and the requested scopes.
    user_id = token_data["user_id"]
    scopes = token_data["scope"]

    user_info = {
        "sub": user_id, # Subject (user ID)
        "username": user_id,
        "scopes": scopes
    }
    # Add more user details based on scopes (e.g., email, name, etc.)
    return jsonify(user_info)


